import { CardContainer } from "./styles"

export const CharacterCard = ({name, image, actor}) => {
    return (
        <CardContainer>
            <h3>{name}</h3>
            <img src="https://www.mundopositivo.com.br/wp-content/uploads/2022/09/fim-de-harry-potter-nao-e-feliz-e-te-engana-ha-anos-1.jpg" />
            <p>Ator: Daniel Radcliff</p>
            <button>Ver detalhes</button>
        </CardContainer>
    )
}
